[package]
name = "kernel"
version = "0.1.0"
edition = "2021"

[features]
qemu = []
default = ["qemu"]

[dependencies]
riscv = { git = "https://github.com/rcore-os/riscv", features = ["inline-asm"] }
lazy_static = { version = "1.4.0", features = ["spin_no_std"] }
buddy_system_allocator = "0.9.1"
bitflags = "2.5.0"
xmas-elf = "0.9.1"
log = "0.4"
virtio-drivers = { git = "https://github.com/rcore-os/virtio-drivers", rev = "4ee80e5" }
async-trait = "0.1.53"
async-task = { version = "4.7.1", default-features = false }
fatfs = { git = "https://github.com/rafalh/rust-fatfs", default-features = false, features = ["lfn", "alloc"] }
spin = { version = "0.9.8", features = ["mutex", "spin_mutex"]}
sbi-rt = { version = "0.0.3", features = ["legacy"] }

TARGET := riscv64gc-unknown-none-elf
MODE := release
KERNEL_ELF := target/$(TARGET)/$(MODE)/kernel

BOARD := qemu
SBI := opensbi
BOOTLOADER := ../bootloader/$(SBI)-$(BOARD).bin

OBJCOPY := rust-objcopy --binary-architecture=riscv64

build: env kernel
	@cp $(KERNEL_ELF) ../kernel-qemu
	@cp $(BOOTLOADER) ../sbi-qemu

env:
	# @(rustup target list | grep "riscv64gc-unknown-none-elf (installed)") || rustup target add $(TARGET)
	# @cargo install cargo-binutils
	# @rustup component add rust-src
	# @rustup component add llvm-tools

kernel:
	@cd ../user && cargo build --release
	@cp src/linker-qemu.ld src/linker.ld
	@cargo build --release
	@rm src/linker.ld

clean:
	@cargo clean

.PHONY: build env kernel clean

//! 这是内核的入口
//! 先通过引入```entry.asm```来设置好内核栈之类的参数，再调用```rust_main()```进入内核 
//! ```link_app.S```用来将 initproc 和 shell 与内核链接在一起
//! 
//! ### TODO
//! - 增加多核启动功能
//! - 去除```link_app.S```，改用从硬盘读取程序

#![no_std]
#![no_main]
#![deny(missing_docs)]
#![allow(improper_ctypes)]
#![feature(panic_info_message)]
#![feature(alloc_error_handler)]
#![feature(negative_impls)]
#![feature(sync_unsafe_cell)]
#![feature(linked_list_remove)]
#![allow(internal_features)]
#![feature(core_intrinsics)]

extern crate alloc;

mod config;
mod driver;
mod fs;
mod klib;
mod mm;
mod sbi;
mod syscall;
mod task;
mod timer;
mod trap;

use crate::sbi::shutdown;
use core::arch::global_asm;

global_asm!(include_str!("entry.asm"));
global_asm!(include_str!("link_app.S"));

/// 清除 BSS 段
fn clear_bss() {
    extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        core::slice::from_raw_parts_mut(sbss as usize as *mut u8, ebss as usize - sbss as usize)
            .fill(0);
    }
}

/// 内核的入口函数，进行各种初始化，最终调用 initproc
#[no_mangle]
pub fn rust_main() {
    clear_bss();
    task::smp::init();
    task::smp::set_hart_stack();
    // klib::logger::init();
    mm::init();
    trap::trap_handler::init();
    trap::trap_handler::enable_timer_interrupt();
    timer::set_next_trigger();
    fs::init();
    task::loader::add_initproc();
    task::task_queue::run_until_idle();
    shutdown(false);
}

pub mod address;
pub mod frame_allocator;
pub mod heap_allocator;
pub mod address_space;
pub mod page;
pub mod page_cache;
pub mod page_table;

/// initiate heap allocator, frame allocator and kernel space
pub fn init() {
    heap_allocator::init_heap();
    frame_allocator::init_frame_allocator();
    address_space::kernel_space::init_kernel_space();
    unsafe {
        address_space::kernel_space::KERNEL_SPACE
            .as_ref()
            .expect("KERNEL SPACE not init yet")
            .activate();
    }
}

//! 实现文件系统
//! 支持FAT32文件系统
//! 并在系统启动时初始化各个文件系统模块


pub mod devfs;
pub mod fat32fs;
